changeSet.sql:
CREATE TABLE technology_categories_metadata (
id serial,
technology_category_id int4 NOT NULL,
key character varying (255) NOT NULL,
value character varying (4096),

CONSTRAINT pk_technology_categories_metadata PRIMARY KEY (id),
CONSTRAINT fk_technology_categories_metadata_to_technology_categories FOREIGN KEY (technology_category_id)
REFERENCES technology_categories(id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);

CREATE INDEX i_technology_categories_metadata_technology_category_id ON
technology_categories_metadata USING btree (technology_category_id);
CREATE UNIQUE INDEX ui_technology_categories_metadata_technology_category_id_key ON
technology_categories_metadata (technology_category_id, key);
